const ALL_COURSES: CourseData[] = [groeneBoek, tweedeRonde, derdeRonde, hollandacaOgreniyoruz, ...atolyesiCourses];

// ─── Seed function ──────────────────────────────────────────────────────────

async function main() {
    console.log("🌱 Seeding courses...");

    for (const course of ALL_COURSES) {
        const courseData = {
            title: course.title,
            description: course.description,
            emoji: course.emoji,
            color: course.color,
            order: course.order,
            category: course.category,
            subcategory: course.subcategory,
        };

        await prisma.course.upsert({
            where: { id: course.id },
            update: courseData,
            create: { id: course.id, ...courseData },
        });

        for (let index = 0; index < course.lessons.length; index++) {
            const lesson = course.lessons[index];
            const lessonData = {
                title: lesson.title,
                order: index,
                content: ((lesson as any).content || lesson.scenario) as object,
                courseId: course.id,
            };

            await prisma.lesson.upsert({
                where: { id: lesson.id },
                update: lessonData,
                create: { id: lesson.id, ...lessonData },
            });
        }

        console.log(`  ✓ ${course.emoji} ${course.title} (${course.lessons.length} ders)`);
    }

    const courseCount = await prisma.course.count();
    const lessonCount = await prisma.lesson.count();
    console.log(`\n✅ Done: ${courseCount} kurs, ${lessonCount} ders.`);
}

main()
    .catch(e => {
        console.error("❌ Seed failed:", e);
        process.exit(1);
    })
    .finally(() => prisma.$disconnect());
